    65→  sessionId: string;
    66→  summary: string;
    67→  keywords: string[];
    68→  startedAt: string;
    69→  endedAt: string;
    70→}
    71→
    72→// ─── Mapping helpers ──────────────────────────────────────────────────────────
    73→
    74→function mapSummary(s: {
    75→  intent: string;
    76→  outcome: string;
    77→  learningsRepo: string | null;
    78→  learningsCode: string | null;
    79→  learningsWorkflow: string | null;
    80→  friction: string | null;
    81→  openItems: string | null;
    82→}) {
    83→  return {
    84→    intent: s.intent,
    85→    outcome: s.outcome,
    86→    repoLearnings:     s.learningsRepo     ? (JSON.parse(s.learningsRepo)     as string[]) : [],
    87→    codeLearnings:     s.learningsCode     ? (JSON.parse(s.learningsCode)     as Array<{ path: string; finding: string }>) : [],
    88→    workflowLearnings: s.learningsWorkflow ? (JSON.parse(s.learningsWorkflow) as string[]) : [],
    89→    friction:          s.friction          ? (JSON.parse(s.friction)          as string[]) : [],
    90→    openItems:         s.openItems         ? (JSON.parse(s.openItems)         as string[]) : [],
    91→  };
    92→}
    93→
    94→function mapEvent(e: {
    95→  id: number;
    96→  timestamp: Date;
    97→  event: string;
    98→  sessionId: string;
    99→  blocked: boolean;
   100→  data: string;
   101→  summary: string | null;
   102→  keywords: string | null;
   103→}): EventResponse {
   104→  let parsedData: unknown;
   105→  try {
   106→    parsedData = JSON.parse(e.data);
   107→  } catch {
   108→    parsedData = e.data;
   109→  }
   110→  return {
   111→    id: e.id,
   112→    timestamp: e.timestamp.toISOString(),
   113→    event: e.event,
   114→    sessionId: e.sessionId,
   115→    blocked: e.blocked,
   116→    data: parsedData,
   117→    summary: e.summary,
   118→    keywords: e.keywords ? (JSON.parse(e.keywords) as string[]) : [],
   119→  };
   120→}
