   308→  // GET /api/v2/sessions/:id/log-events
   309→  app.get("/api/v2/sessions/:id/log-events", async (req, res) => {
   310→    try {
   311→      const events = await db.logEvent.findMany({
   312→        where:   { sessionId: req.params.id },
